function solve(s, order, k) {
    const n = s.length;
    const marked = new Array(n).fill(false);
    let totalSubstrings = 0;
    let activeCount = 0;
    let result = -1;

    for (let t = 0; t < n; t++) {
        const pos = order[t];
        if (marked[pos]) continue;
        marked[pos] = true;
        activeCount++;

        // The number of new valid substrings is the number of substrings that include this '*' but not any previous '*'
        // This can be calculated as (left + 1) * (right + 1)
        let left = 0;
        let right = 0;

        // Count contiguous unmarked characters to the left
        for (let i = pos - 1; i >= 0 && !marked[i]; i--) {
            left++;
        }

        // Count contiguous unmarked characters to the right
        for (let i = pos + 1; i < n && !marked[i]; i++) {
            right++;
        }

        const newSubstrings = (left + 1) * (right + 1);
        totalSubstrings += newSubstrings;

        if (totalSubstrings >= k) {
            result = t;
            break;
        }
    }

    return result;
}

